import{_ as e,c as r,o as l,a5 as i}from"./chunks/framework.BtqC3pLB.js";const _=JSON.parse('{"title":"日本 -> 北海道 -> 北海道","description":"","frontmatter":{},"headers":[],"relativePath":"日本/北海道/index.md","filePath":"docs/日本/北海道/index.md","lastUpdated":1766646134000}'),t={name:"日本/北海道/index.md"};function n(o,a,s,h,d,c){return l(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="北海道" tabindex="-1">北海道 <a class="header-anchor" href="#北海道" aria-label="Permalink to “北海道”">​</a></h1><h2 id="北國風光" tabindex="-1">北國風光 <a class="header-anchor" href="#北國風光" aria-label="Permalink to “北國風光”">​</a></h2><p>北海道是日本第二大島，也是最北端的行政區，以其壯麗的自然風光、豐富的戶外活動和美味的海鮮而聞名。</p><h2 id="主要區域" tabindex="-1">主要區域 <a class="header-anchor" href="#主要區域" aria-label="Permalink to “主要區域”">​</a></h2><ul><li><strong><a href="./札幌/">札幌</a>：</strong> 北海道的首府，擁有豐富的購物、美食和文化景點。</li><li><strong><a href="./函館/">函館</a>：</strong> 浪漫的港口城市，以其百萬夜景和新鮮海產聞名。</li><li><strong><a href="./旭川/">旭川</a>：</strong> 北海道第二大城，擁有著名的旭山動物園。</li><li><strong><a href="./登別/">登別</a>：</strong> 著名的溫泉勝地，以地獄谷與豐富的溫泉泉質聞名。</li><li><strong><a href="./小樽/">小樽</a>：</strong> 浪漫的海港城市，以運河、歷史建築與玻璃工藝聞名。</li><li><strong><a href="./美瑛/">美瑛</a>：</strong> 擁有壯麗丘陵美景的小鎮，以青池與白髭瀑布聞名。</li></ul><h2 id="必訪景點" tabindex="-1">必訪景點 <a class="header-anchor" href="#必訪景點" aria-label="Permalink to “必訪景點”">​</a></h2><ul><li><strong><a href="./函館/景點/函館山">函館山</a>：</strong> 以其美麗的夜景而聞名，可以俯瞰函館市的景色。</li><li><strong><a href="./旭川/景點/旭山動物園">旭山動物園</a>：</strong> 以其獨特的動物展示方式而聞名，可以近距離觀察各種動物。</li><li><strong><a href="./函館/景點/大沼國定公園">大沼國定公園</a>：</strong> 位於渡島半島東側，是北海道內面積最小的國定公園。</li></ul><h2 id="交通資訊" tabindex="-1">交通資訊 <a class="header-anchor" href="#交通資訊" aria-label="Permalink to “交通資訊”">​</a></h2><p>前往北海道可以搭乘飛機至新千歲機場或函館機場，或是搭乘新幹線至札幌車站。在北海道內移動，<a href="./交通/JR北海道鐵路周遊券">JR 北海道鐵路周遊券</a>是一個非常划算的選擇。此外，冬季也可以前往各山區體驗<a href="./活動/滑雪">滑雪活動</a>。</p><h2 id="溫馨提示" tabindex="-1">溫馨提示 <a class="header-anchor" href="#溫馨提示" aria-label="Permalink to “溫馨提示”">​</a></h2><ul><li>北海道的冬季非常寒冷，請注意保暖。</li><li>北海道以其美味的海鮮而聞名，例如螃蟹和海膽，不妨品嚐一下當地的特產。</li><li>北海道的面積廣闊，建議事先規劃好行程，以便更好地體驗當地的自然風光。</li></ul>',11)])])}const g=e(t,[["render",n]]);export{_ as __pageData,g as default};
